CREATE TABLE IF NOT EXISTS users (id SERIAL PRIMARY KEY, username VARCHAR(50) UNIQUE NOT NULL, password_hash VARCHAR(128) NOT NULL, email VARCHAR(100), tier VARCHAR(10) DEFAULT 'free', theme VARCHAR(10) DEFAULT 'dark', is_active BOOLEAN DEFAULT true, login_attempts INT DEFAULT 0, locked_until TIMESTAMP, vip_expires_at TIMESTAMP, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS mt5_accounts (id SERIAL PRIMARY KEY, user_id INT REFERENCES users(id) ON DELETE CASCADE, login BIGINT NOT NULL, password_encrypted VARCHAR(500) NOT NULL, server VARCHAR(100) NOT NULL, account_name VARCHAR(100), is_active BOOLEAN DEFAULT true, created_at TIMESTAMP DEFAULT NOW(), UNIQUE(user_id, login));
CREATE TABLE IF NOT EXISTS trades (id SERIAL PRIMARY KEY, user_id INT REFERENCES users(id), mt5_account_id INT REFERENCES mt5_accounts(id), signal VARCHAR(5), entry_price DECIMAL(12,2), exit_price DECIMAL(12,2), sl DECIMAL(12,2), tp DECIMAL(12,2), lot_size DECIMAL(8,4) DEFAULT 0.01, ticket BIGINT, pnl DECIMAL(12,2) DEFAULT 0, status VARCHAR(20) DEFAULT 'open', created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS payments (id SERIAL PRIMARY KEY, tx_id VARCHAR(150) UNIQUE NOT NULL, from_address VARCHAR(150), amount DECIMAL(12,2), network VARCHAR(20) DEFAULT 'TRC20', status VARCHAR(20) DEFAULT 'pending', user_id INT REFERENCES users(id), created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS pending_deposits (id SERIAL PRIMARY KEY, user_id INT REFERENCES users(id), expected_amount DECIMAL(12,2), status VARCHAR(20) DEFAULT 'pending', matched_tx_id VARCHAR(150), created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS daily_stats (id SERIAL PRIMARY KEY, user_id INT REFERENCES users(id), date DATE DEFAULT CURRENT_DATE, trades_count INT DEFAULT 0, wins INT DEFAULT 0, losses INT DEFAULT 0, pnl DECIMAL(12,2) DEFAULT 0, UNIQUE(user_id, date));
